if (!function_exists('prod_t')) {
  function prod_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('prod_h')) {
  function prod_h($key, $fallback = '') { return htmlspecialchars((string) prod_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('prod_js')) {
  function prod_js($key, $fallback = '') { return json_encode(prod_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-d');$defaultTo=date('Y-m-d');
$plants=$db->query("SELECT DISTINCT plant_code FROM erp_production_activity_log WHERE plant_code IS NOT NULL AND plant_code<>'' UNION SELECT DISTINCT plant FROM production_order WHERE plant IS NOT NULL AND plant<>'' ORDER BY plant_code");
$shifts=$db->query("SELECT id,kode_shift,nama_shift,jam_mulai,jam_selesai FROM erp_shift WHERE status='Aktif' ORDER BY kode_shift");
$kpi=$db->fetch("SELECT COUNT(*) manual_doc,SUM(severity='WARNING') warning_doc,SUM(severity='CRITICAL') critical_doc FROM erp_production_activity_log WHERE activity_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
$dt=$db->fetch("SELECT COUNT(*) downtime_doc FROM erp_production_downtime WHERE downtime_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
$cf=$db->fetch("SELECT COUNT(*) confirmation_doc FROM production_order_confirmation WHERE COALESCE(posting_date,DATE(confirmation_date)) BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
