s->kode_shift,ENT_QUOTES,'UTF-8');?>"><?=htmlspecialchars($s->kode_shift.' - '.$s->nama_shift,ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><label class="control-label col-lg-1"><?=prod_h('production_type', 'Type');?></label><div class="col-lg-2"><select id="filter_activity_type" class="form-control"><option value=""><?=prod_h('common_all', 'All');?></option><option>ORDER_START</option><option>OPERATION_START</option><option>OPERATION_FINISH</option><option>MATERIAL_ISSUE</option><option>CONFIRMATION</option><option>DOWNTIME</option><option>QUALITY_CHECK</option><option>CLEANING</option><option>HANDOVER</option><option>NOTE</option><option>STOP</option><option>OTHER</option></select></div><div class="col-lg-2"><select id="filter_severity" class="form-control"><option value="">Severity</option><option>INFO</option><option>WARNING</option><option>CRITICAL</option></select></div></div><div class="form-group"><label class="control-label col-lg-2"><?=prod_h('common_search', 'Search');?></label><div class="col-lg-6"><input id="filter_keyword" class="form-control" placeholder="Activity no, PO, operator, work center, catatan"></div><div class="col-lg-4"><button id="btn_filter_pal" class="btn btn-primary"><i class="fa fa-filter"></i> <?=prod_h('common_filter', 'Filter');?></button> <button id="btn_reset_pal" class="btn btn-default"><i class="fa fa-refresh"></i> <?=prod_h('common_reset', 'Reset');?></button> <button id="btn_excel_pal" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=prod_h('common_export_excel', 'Export Excel');?></button></div></div></form></div></div>
