  <div id="modal_pal" class="modal fade"><div class="modal-dialog modal-lg" style="width:92%"><form id="form_pal" class="modal-content pal-form"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title">Add Production Activity</h4></div><div class="modal-body"><div class="row"><div class="col-md-6 form-group"><label><?=prod_h('production_order', 'Production Order');?></label><select name="production_id" id="production_id" class="form-control"></select><small class="text-muted">Opsional jika aktivitas umum shop floor.</small></div><div class="col-md-6 form-group"><label><?=prod_h('production_operation', 'Operation');?></label><select name="operation_id" id="operation_id" class="form-control"></select></div></div><div class="row"><div class="col-md-3 form-group"><label class="required-label"><?=prod_h('production_work_center', 'Work Center');?></label><select name="work_center" id="work_center" class="form-control" required></select><input type="hidden" name="work_center_name" id="work_center_name"></div><div class="col-md-2 form-group"><label><?=prod_h('production_plant', 'Plant');?></label><input name="plant_code" id="plant_code" class="form-control"></div><div class="col-md-3 form-group"><label><?=prod_h('production_shift', 'Shift');?></label><select name="shift_id" id="shift_id" class="form-control"><option value="">-</option><?php foreach($shifts as $s){ ?><option value="<?=intval($s->id);?>"><?=htmlspecialchars($s->kode_shift.' - '.$s->nama_shift.' ('.$s->jam_mulai.'-'.$s->jam_selesai.')',ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><div class="col-md-2 form-group"><label class="required-label">Activity Time</label><input type="datetime-local" name="activity_time" id="activity_time" class="form-control" value="<?=date('Y-m-d\TH:i');?>" required></div><div class="col-md-2 form-group"><label><?=prod_h('production_operator', 'Operator');?></label><input name="operator_name" class="form-control" placeholder="Nama operator"></div></div><div class="row"><div class="col-md-3 form-group"><label class="required-label">Activity Type</label><select name="activity_type" class="form-control" required><option>NOTE</option><option>ORDER_START</option><option>OPERATION_START</option><option>OPERATION_FINISH</option><option>MATERIAL_ISSUE</option><option>QUALITY_CHECK</option><option>CLEANING</option><option>HANDOVER</option><option>STOP</option><option>OTHER</option></select></div><div class="col-md-3 form-group"><label>Severity</label><select name="severity" class="form-control"><option>INFO</option><option>WARNING</option><option>CRITICAL</option></select></div><div class="col-md-6 form-group"><label class="required-label">Activity Text</label><input name="activity_text" class="form-control" required placeholder="Contoh: Handover shift, mesin normal, quality check OK"></div></div><div class="form-group"><label>Action Taken</label><textarea name="action_taken" class="form-control" rows="2" placeholder="Tindakan yang dilakukan jika ada"></textarea></div><div class="form-group"><label><?=prod_h('common_remarks', 'Remarks');?></label><textarea name="remarks" class="form-control" rows="2" placeholder="Catatan tambahan"></textarea></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=prod_h('common_close', 'Close');?></button><button type="submit" class="btn btn-primary"><i class="fa fa-save"></i> Save Activity</button></div></form></div></div>
