<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function palError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_activity_log_process_failed', 'Production Activity Log failed to process.');?>);$('.error_data_delete').fadeIn();}
function palFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant:$('#filter_plant').val(),work_center:$('#filter_work_center').val(),shift:$('#filter_shift').val(),activity_type:$('#filter_activity_type').val(),severity:$('#filter_severity').val(),source_type:$('#filter_source_type').val(),keyword:$('#filter_keyword').val()};}
function palQuery(){return $.param(palFilters());}
$(function(){if($.fn.datepicker){$('.pal-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_shift,#filter_activity_type,#filter_severity,#filter_source_type,#shift_id').select2({width:'100%',allowClear:true});$('#production_id').select2({width:'100%',allowClear:true,placeholder:<?=prod_js('production_search_production_order', 'Search Production Order...');?>,minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=order_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});$('#operation_id').select2({width:'100%',allowClear:true,placeholder:'Pilih operation...',ajax:{url:'<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=operations',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||'',production_id:$('#production_id').val()};},processResults:function(d){return{results:d.results||[]};}}});$('#work_center').select2({width:'100%',allowClear:true,placeholder:'Cari Work Center...',minimumInputLength:0,ajax:{url:'<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=work_center_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
var dt=$('#dtb_production_activity_log').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'82px',targets:1}],ajax:{url:'<?=base_admin();?>modul/production_activity_log/production_activity_log_data.php',type:'post',data:function(d){$.extend(d,palFilters());},error:function(xhr){console.log(xhr.responseText);palError(<?=prod_js('production_activity_load_failed', 'Activity data failed to load.');?>);}}});
$('#btn_filter_pal').click(function(){dt.draw();});$('#filter_keyword,#filter_work_center').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_pal').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant,#filter_shift,#filter_activity_type,#filter_severity,#filter_source_type').val('').trigger('change');$('#filter_work_center,#filter_keyword').val('');dt.draw();});$('#btn_excel_pal').click(function(){window.location='<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=excel&'+palQuery();});
$('#btn_add_pal').click(function(){document.getElementById('form_pal').reset();$('#production_id,#operation_id,#work_center,#shift_id').val(null).trigger('change');$('#activity_time').val('<?=date('Y-m-d\TH:i');?>');$('#modal_pal').modal({backdrop:'static',keyboard:false});});
$('#production_id').on('select2:select',function(e){var d=e.params.data;$('#plant_code').val(d.plant||'');$('#operation_id').val(null).trigger('change');});$('#operation_id').on('select2:select',function(e){var d=e.params.data;if(d.work_center){var opt=new Option(d.work_center,d.work_center,true,true);$('#work_center').append(opt).trigger('change');$('#work_center_name').val(d.work_center);}});$('#work_center').on('select2:select',function(e){$('#work_center_name').val(e.params.data.work_center_name||e.params.data.text||'');});
$('#form_pal').submit(function(e){e.preventDefault();$.post('<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=save',$(this).serialize(),function(r){if(r.status==='good'){$('#modal_pal').modal('hide');dt.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Activity '+(r.activity_no||'')+' tersimpan.','success');}else palError(r.error_message);},'json').fail(function(xhr){console.log(xhr.responseText);palError('Activity gagal disimpan.');});});
$(document).on('click','.btn-pal-detail',function(){$.post('<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=detail',{id:$(this).data('id'),source_type:$(this).data('source')},function(html){$('#pal_detail_body').html(html);$('#modal_detail_pal').modal('show');}).fail(function(){palError('Detail gagal dibuka.');});});
$(document).on('click','.btn-pal-cancel',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:'Cancel Activity?',text:no,input:'text',inputLabel:'Reason',showCancelButton:true,confirmButtonText:'Cancel'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/production_activity_log/production_activity_log_action.php?act=cancel',{id:id,reason:x.value||''},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Activity dibatalkan.','success');}else palError(r.error_message);},'json').fail(function(){palError(<?=prod_js('production_cancel_failed', 'Cancel failed.');?>);});});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
